/* ============================================================================
   transcript-assets.js — binary assets for the Transcript/Grades system.

   Everything is embedded as base64 so the transcript renders and downloads
   with zero network access (same policy as /vendor):
     - crestPng: the institution's crest, taken from the approved transcript.
     - garamondRegular/garamondBold: EB Garamond (SIL OFL 1.1), subset to
       Latin. Closest open-licensed match to the Adobe Garamond Pro used on
       the approved paper transcript; embedded into both the on-screen
       preview (@font-face) and the downloaded PDFs (jsPDF VFS).
   ============================================================================ */
(function (root) {
  'use strict';
  root.CESTIS_TRANSCRIPT_ASSETS = {
    crestPng: '',
    garamondRegular: '',
    garamondBold: ''
  };
})(typeof window !== 'undefined' ? window : this);
